/**
 * Delete events older than a given number of days.
 */
export function pruneOldEvents(db: Database.Database, maxAgeDays: number): number {
	const cutoff = new Date(Date.now() - maxAgeDays * 24 * 60 * 60 * 1000).toISOString();
	const result = db.prepare(
		`DELETE FROM events WHERE timestamp < ?`,
	).run(cutoff);
	return result.changes;
}

import type Database from "better-sqlite3";

// ── Types ──────────────────────────────────────────────────────────────────────

export interface SearchResult {
	id: string;
	score: number;
	title: string;
	content: string;
	category: string;
}

export interface SearchOptions {
	maxResults?: number;
	rrfK?: number;
	proximityBoost?: number;
	scope?: string;
	detail?: "compact" | "medium" | "full";
}

// ── Porter stemmer search ──────────────────────────────────────────────────────

export function porterSearch(
	db: Database.Database,
	query: string,
	limit: number,
): SearchResult[] {
	const sql = `
		SELECT source_id, title, content, category, rank
		FROM chunks
		WHERE chunks MATCH ?
		ORDER BY bm25(chunks)
		LIMIT ?
	`;
	try {
		const rows = db.prepare(sql).all(query, limit) as Array<{
			source_id: string;
			title: string;
			content: string;
			category: string;
			rank: number;
		}>;
		return rows.map((r) => ({
			id: r.source_id,
			score: -r.rank,
			title: r.title ?? "",
			content: r.content ?? "",
			category: r.category ?? "",
		}));
	} catch {
		return [];
	}
}

// ── Trigram search ─────────────────────────────────────────────────────────────

export function trigramSearch(
	db: Database.Database,
	query: string,
	limit: number,
): SearchResult[] {
	// Trigram FTS5 requires wrapping query in quotes for phrase matching
	const trigramQuery = `"${query.replace(/"/g, '""')}"`;
	const sql = `
		SELECT source_id, content, rank
		FROM chunks_trigram
		WHERE chunks_trigram MATCH ?
		ORDER BY bm25(chunks_trigram)
		LIMIT ?
	`;
	try {
		const rows = db.prepare(sql).all(trigramQuery, limit) as Array<{
			source_id: string;
			content: string;
			rank: number;
		}>;
		return rows.map((r) => ({
			id: r.source_id,
			score: -r.rank,
			title: "",
			content: r.content ?? "",
			category: "",
		}));
	} catch {
		return [];
	}
}

// ── Reciprocal Rank Fusion ─────────────────────────────────────────────────────

export function rrf(
	porterResults: SearchResult[],
	trigramResults: SearchResult[],
	K: number = 60,
): SearchResult[] {
	const scores = new Map<string, { score: number; title: string; content: string; category: string }>();

	for (const [rank, result] of porterResults.entries()) {
		const existing = scores.get(result.id);
		const addedScore = 1 / (K + rank + 1);
		if (existing) {
			existing.score += addedScore;
		} else {
			scores.set(result.id, {
				score: addedScore,
				title: result.title,
				content: result.content,
				category: result.category,
			});
		}
	}

	for (const [rank, result] of trigramResults.entries()) {
		const existing = scores.get(result.id);
		const addedScore = 1 / (K + rank + 1);
		if (existing) {
			existing.score += addedScore;
			// Keep porter title if available
			if (!existing.title && result.title) existing.title = result.title;
		} else {
			scores.set(result.id, {
				score: addedScore,
				title: result.title,
				content: result.content,
				category: result.category,
			});
		}
	}

	return [...scores.entries()]
		.sort((a, b) => b[1].score - a[1].score)
		.map(([id, data]) => ({
			id,
			score: data.score,
			title: data.title,
			content: data.content,
			category: data.category,
		}));
}

// ── Proximity reranking ────────────────────────────────────────────────────────

export function proximityRerank(
	results: SearchResult[],
	query: string,
	boost: number = 1.5,
): SearchResult[] {
	const terms = query.toLowerCase().split(/\s+/).filter((t) => t.length > 0);
	if (terms.length <= 1) return results;

	return results.map((result) => {
		const lower = result.content.toLowerCase();
		const positions: number[][] = terms.map((term) => {
			const pos: number[] = [];
			let idx = 0;
			while (true) {
				const found = lower.indexOf(term, idx);
				if (found === -1) break;
				pos.push(found);
				idx = found + 1;
			}
			return pos;
		});

		// If any term not found, no proximity bonus
		if (positions.some((p) => p.length === 0)) return result;

		// Find minimum span covering one occurrence of each term
		let minSpan = Infinity;
		for (const pos0 of positions[0]!) {
			const current: number[] = [pos0];
			for (let t = 1; t < positions.length; t++) {
				// Find closest position in term t to the last added position
				const lastPos = current[current.length - 1]!;
				let closest = positions[t]![0]!;
				for (const p of positions[t]!) {
					if (Math.abs(p - lastPos) < Math.abs(closest - lastPos)) {
						closest = p;
					}
				}
				current.push(closest);
			}
			const span = Math.max(...current) - Math.min(...current);
			minSpan = Math.min(minSpan, span);
		}

		// Boost inversely proportional to span (closer terms = higher boost)
		const contentLength = Math.max(result.content.length, 1);
		const proximityScore = minSpan < contentLength ? boost * (1 - minSpan / contentLength) : 0;

		return {
			...result,
			score: result.score + proximityScore,
		};
	}).sort((a, b) => b.score - a.score);
}

// ── Unified search ─────────────────────────────────────────────────────────────

export function search(
	db: Database.Database,
	query: string,
	opts: SearchOptions = {},
): SearchResult[] {
	const maxResults = opts.maxResults ?? 5;
	const rrfK = opts.rrfK ?? 60;
	const boost = opts.proximityBoost ?? 1.5;
	const fetchLimit = maxResults * 4; // fetch more for reranking

	const porter = porterSearch(db, query, fetchLimit);
	const trigram = trigramSearch(db, query, fetchLimit);

	let fused = rrf(porter, trigram, rrfK);
	fused = proximityRerank(fused, query, boost);

	// Scope filter
	if (opts.scope && opts.scope !== "all") {
		fused = fused.filter((r) => r.category === opts.scope);
	}

	return fused.slice(0, maxResults);
}

import * as fs from "node:fs";
import * as path from "node:path";
import type Database from "better-sqlite3";

/**
 * Ensures the .pi-memory/ directory exists with subdirectories.
 */
export function ensurePiMemoryDir(cwd: string): string {
	const dir = path.join(cwd, ".pi-memory");
	fs.mkdirSync(dir, { recursive: true });
	fs.mkdirSync(path.join(dir, "mental-models"), { recursive: true });
	fs.mkdirSync(path.join(dir, "solutions"), { recursive: true });
	return dir;
}

/**
 * Generate/update PI_MEMORY.md at the project root.
 * Reads current state from DB to create a compact summary.
 */
export function generatePIMemoryMd(db: Database.Database, cwd: string): void {
	const now = new Date().toISOString().split("T")[0];
	const projectName = path.basename(cwd);

	// Count solutions by type
	const bugCount = (db.prepare(`SELECT COUNT(*) as c FROM solutions WHERE problem_type = 'bug'`).get() as { c: number }).c;
	const knowledgeCount = (db.prepare(`SELECT COUNT(*) as c FROM solutions WHERE problem_type = 'knowledge'`).get() as { c: number }).c;
	const decisionCount = (db.prepare(`SELECT COUNT(*) as c FROM solutions WHERE problem_type = 'decision'`).get() as { c: number }).c;

	// Recent solutions
	const recentSolutions = db.prepare(
		`SELECT title, problem_type, severity FROM solutions ORDER BY updated_at DESC LIMIT 5`,
	).all() as Array<{ title: string; problem_type: string; severity: string | null }>;

	// Recent decisions
	const recentDecisions = db.prepare(
		`SELECT title, content FROM solutions WHERE problem_type = 'decision' ORDER BY updated_at DESC LIMIT 3`,
	).all() as Array<{ title: string; content: string }>;

	// Read architecture/conventions if they exist
	let architectureSection = "_Not yet documented._";
	let conventionsSection = "_Not yet documented._";

	const archPath = path.join(cwd, ".pi-memory", "architecture.md");
	if (fs.existsSync(archPath)) {
		const content = fs.readFileSync(archPath, "utf-8");
		architectureSection = content.slice(0, 500);
	}

	const convPath = path.join(cwd, ".pi-memory", "conventions.md");
	if (fs.existsSync(convPath)) {
		const content = fs.readFileSync(convPath, "utf-8");
		conventionsSection = content.slice(0, 500);
	}

	// Active patterns
	let activePatterns = "";
	if (recentSolutions.length > 0) {
		activePatterns = recentSolutions
			.map((s) => `- ${s.title} (${s.problem_type}${s.severity ? `, ${s.severity}` : ""})`)
			.join("\n");
	} else {
		activePatterns = "_No solutions recorded yet._";
	}

	// Recent decisions
	let decisionsSection = "";
	if (recentDecisions.length > 0) {
		decisionsSection = recentDecisions
			.map((d) => `- **${d.title}**: ${d.content.slice(0, 200)}`)
			.join("\n");
	} else {
		decisionsSection = "_No decisions recorded yet._";
	}

	const content = `# Project Memory: ${projectName}
> Auto-generated by pi-memory. Updated: ${now}

## Architecture
${architectureSection}

## Conventions
${conventionsSection}

## Active Patterns
${activePatterns}

## Recent Decisions
${decisionsSection}

## Stats
- Bug solutions: ${bugCount}
- Knowledge patterns: ${knowledgeCount}
- Decisions: ${decisionCount}
`;

	fs.writeFileSync(path.join(cwd, "PI_MEMORY.md"), content, "utf-8");
}

/**
 * Update a markdown file in .pi-memory/ (append section or overwrite).
 */
export function updateMarkdownFile(
	cwd: string,
	name: string,
	content: string,
): void {
	const filePath = path.join(cwd, ".pi-memory", `${name}.md`);
	ensurePiMemoryDir(cwd);
	fs.writeFileSync(filePath, content, "utf-8");
}

/**
 * Read a markdown file from .pi-memory/.
 */
export function readMarkdownFile(cwd: string, name: string): string | null {
	const filePath = path.join(cwd, ".pi-memory", `${name}.md`);
	try {
		return fs.readFileSync(filePath, "utf-8");
	} catch {
		return null;
	}
}

import * as crypto from "node:crypto";
