import * as fs from "node:fs";
import type Database from "better-sqlite3";

export interface MemoryStatusInput {
	action: "status" | "stats" | "reindex" | "compact" | "export";
	format?: "text" | "json";
}

export interface MemoryStats {
	solutions: number;
	sources: number;
	events: number;
	mentalModels: number;
	dbSize: number;
	lastUpdated: string | null;
}

function getStats(db: Database.Database, dbPath: string): MemoryStats {
	const solutions = (db.prepare(`SELECT COUNT(*) as c FROM solutions`).get() as { c: number }).c;
	const sources = (db.prepare(`SELECT COUNT(*) as c FROM sources`).get() as { c: number }).c;
	const events = (db.prepare(`SELECT COUNT(*) as c FROM events`).get() as { c: number }).c;
	const mentalModels = (db.prepare(`SELECT COUNT(*) as c FROM mental_models`).get() as { c: number }).c;

	let dbSize = 0;
	try {
		const stat = fs.statSync(dbPath);
		dbSize = stat.size;
	} catch { /* ignore */ }

	const lastSolution = db.prepare(
		`SELECT updated_at FROM solutions ORDER BY updated_at DESC LIMIT 1`,
	).get() as { updated_at: string } | undefined;

	return {
		solutions,
		sources,
		events,
		mentalModels,
		dbSize,
		lastUpdated: lastSolution?.updated_at ?? null,
	};
}

function formatBytes(bytes: number): string {
	if (bytes < 1024) return `${bytes}B`;
	if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)}KB`;
	return `${(bytes / (1024 * 1024)).toFixed(1)}MB`;
}

/**
 * Handle the memory_status tool invocation.
 */
export function handleMemoryStatus(db: Database.Database, dbPath: string, input: MemoryStatusInput): string {
	const format = input.format ?? "text";

	switch (input.action) {
		case "status":
		case "stats": {
			const stats = getStats(db, dbPath);
			if (format === "json") {
				return JSON.stringify(stats, null, 2);
			}
			return [
				`pi-memory Status:`,
				`  Solutions stored: ${stats.solutions}`,
				`  Sources indexed: ${stats.sources}`,
				`  Session events: ${stats.events}`,
				`  Mental models: ${stats.mentalModels}`,
				`  Index size: ${formatBytes(stats.dbSize)}`,
				`  Last updated: ${stats.lastUpdated ?? "never"}`,
			].join("\n");
		}
		case "reindex": {
			// Delete and rebuild FTS5 indexes from sources
			db.exec(`DELETE FROM chunks`);
			db.exec(`DELETE FROM chunks_trigram`);
			const sources = db.prepare(`SELECT id, title, category, metadata FROM sources`).all() as Array<{
				id: string;
				title: string;
				category: string;
				metadata: string;
			}>;
			// Re-insert content from solutions and sources
			const insertChunk = db.prepare(
				`INSERT INTO chunks (source_id, title, content, category) VALUES (?, ?, ?, ?)`,
			);
			const insertTrigram = db.prepare(
				`INSERT INTO chunks_trigram (source_id, content) VALUES (?, ?)`,
			);
			for (const source of sources) {
				const content = source.title; // Use title as content for reindex
				insertChunk.run(source.id, source.title, content, source.category);
				insertTrigram.run(source.id, content);
			}
			return `Reindexed ${sources.length} sources.`;
		}
		case "compact": {
			// VACUUM the database to reclaim space
			db.exec(`VACUUM`);
			const stats = getStats(db, dbPath);
			return `Database compacted. Current size: ${formatBytes(stats.dbSize)}.`;
		}
		case "export": {
			const stats = getStats(db, dbPath);
			if (format === "json") {
				return JSON.stringify({ stats }, null, 2);
			}
			return `Export:\n${JSON.stringify(stats, null, 2)}`;
		}
		default:
			return `Unknown action: ${input.action}`;
	}
}

import type { ExtensionAPI, ExtensionContext } from "@mariozechner/pi-coding-agent";
import * as fs from "node:fs";
import * as path from "node:path";
import { fileURLToPath } from "node:url";
import { loadConfig } from "../config.ts";
import { MemoryDB } from "../store/sqlite.ts";
import { handleMemorySearch, type MemorySearchInput } from "../tools/memory-search.ts";
import { handleMemoryStore, type MemoryStoreInput } from "../tools/memory-store.ts";
import { handleMemoryRecall, type MemoryRecallInput } from "../tools/memory-recall.ts";
import { handleMemoryStatus, type MemoryStatusInput } from "../tools/memory-status.ts";
import { generatePIMemoryMd } from "../memory/hierarchical.ts";
import { autoSeedModels } from "../memory/mental-models.ts";
import { analyzeSession } from "../compound/analyzer.ts";
import { consolidateMemories } from "../memory/reflect.ts";
import { createSessionTracker } from "../continuity/tracker.ts";
import { buildResumeContext, formatResumeContext } from "../continuity/resumer.ts";
import { handleCompaction } from "../continuity/compaction-hook.ts";

let currentCtx: ExtensionContext | undefined;
let memoryDB: MemoryDB | undefined;

function getDB(cwd: string): MemoryDB {
	if (memoryDB && memoryDB.cwd === cwd) return memoryDB;
	memoryDB?.close();
	memoryDB = new MemoryDB(cwd);
	memoryDB.open();
	return memoryDB;
}

export function registerPiMemory(pi: ExtensionAPI): void {
	// ── session_start ─────────────────────────────────────────────────────────
	pi.on("session_start", (_event, ctx) => {
		currentCtx = ctx;
		const config = loadConfig(ctx.cwd);
		if (!config.enabled) return;

		const db = getDB(ctx.cwd);

		// Auto-seed mental models
		if (config.mentalModels.enabled) {
			autoSeedModels(db.getConnection(), config.mentalModels.seeds);
		}

		// Generate PI_MEMORY.md if auto-generate is enabled
		if (config.autoGenerateSummary) {
			try {
				generatePIMemoryMd(db.getConnection(), ctx.cwd);
			} catch { /* non-critical */ }
		}

		// Session resume
		if (config.continuity.enabled && config.continuity.autoResume) {
			try {
				const resumeCtx = buildResumeContext(db.getConnection());
				if (resumeCtx) {
					const prompt = formatResumeContext(resumeCtx, config.continuity.maxResumeContext);
					if (prompt) {
						// Inject resume context as a follow-up message
						const sessionId = (ctx as unknown as Record<string, unknown>).sessionId as string | undefined;
						void sessionId;
					}
				}
			} catch { /* non-critical */ }
		}
	});

	// ── session_shutdown ───────────────────────────────────────────────────────
	pi.on("session_shutdown", () => {
		if (!currentCtx) return;
		const config = loadConfig(currentCtx.cwd);
		const db = memoryDB;
		if (!db?.isOpen) {
			memoryDB?.close();
			memoryDB = undefined;
			currentCtx = undefined;
			return;
		}

		const conn = db.getConnection();

		// Knowledge compounding
		if (config.autoCompound && config.compounding.enabled) {
			try {
				const sessionId = (currentCtx as unknown as Record<string, unknown>).sessionId as string | undefined;
				if (sessionId) {
					analyzeSession(conn, currentCtx.cwd, sessionId, config.compounding.dedupThreshold);
				}
			} catch { /* non-critical */ }
		}

		// Consolidation
		try {
			consolidateMemories(conn, config.maxSolutionsAge);
		} catch { /* non-critical */ }

		// Update PI_MEMORY.md
		if (config.autoGenerateSummary) {
			try {
				generatePIMemoryMd(conn, currentCtx.cwd);
			} catch { /* non-critical */ }
		}

		db.close();
		memoryDB = undefined;
		currentCtx = undefined;
	});

	// ── tool_call tracking ─────────────────────────────────────────────────────
	pi.on("tool_call", (event) => {
		if (!currentCtx || !memoryDB?.isOpen) return;
		const config = loadConfig(currentCtx.cwd);
		if (!config.enabled) return;

		const toolName = (event as { toolName?: string }).toolName;
		if (toolName === "edit" || toolName === "write") {
			const input = (event as { input?: Record<string, unknown> }).input;
			const filePath = typeof input?.file === "string" ? input.file :
				typeof input?.path === "string" ? input.path : undefined;
			if (filePath) {
				const sessionId = (currentCtx as unknown as Record<string, unknown>).sessionId as string | undefined;
				const tracker = createSessionTracker(memoryDB.getConnection(), sessionId ?? "unknown");
				tracker.trackEdit(filePath, 0);
			}
		}
	});

	// ── resources_discover ─────────────────────────────────────────────────────
	try {
		pi.on("resources_discover", () => {
			const extDir = path.resolve(path.dirname(fileURLToPath(import.meta.url)), "..", "..", "skills");
			if (fs.existsSync(extDir)) return { skillPaths: [extDir] };
			return {};
		});
	} catch { /* older Pi without resources_discover */ }

	// ── Register tools ─────────────────────────────────────────────────────────
	try {
		pi.registerTool({
			name: "memory_search",
			description: "Search persistent memory for relevant knowledge, solutions, decisions, and patterns",
			parameters: {
				type: "object",
				properties: {
					query: { type: "string", description: "Natural language query" },
					maxResults: { type: "number", description: "Maximum results to return (default: 5)" },
					scope: {
						type: "string",
						enum: ["all", "solutions", "decisions", "gotchas", "conventions"],
						description: "Search scope filter",
					},
					detail: {
						type: "string",
						enum: ["compact", "medium", "full"],
						description: "Detail level (default: compact)",
					},
				},
				required: ["query"],
			},
			execute: (input: unknown) => {
				const cwd = currentCtx?.cwd ?? process.cwd();
				const db = getDB(cwd);
				return handleMemorySearch(db.getConnection(), input as MemorySearchInput);
			},
		});
	} catch { /* tool registration may not be available */ }

	try {
		pi.registerTool({
			name: "memory_store",
			description: "Store knowledge in persistent memory (gotchas, conventions, decisions, patterns, architecture)",
			parameters: {
				type: "object",
				properties: {
					category: {
						type: "string",
						enum: ["gotcha", "convention", "decision", "pattern", "architecture"],
						description: "Knowledge category",
					},
					title: { type: "string", description: "Title for the stored knowledge" },
					content: { type: "string", description: "Content to store" },
					metadata: {
						type: "object",
						properties: {
							files: { type: "array", items: { type: "string" } },
							tags: { type: "array", items: { type: "string" } },
							severity: { type: "string", enum: ["low", "medium", "high", "critical"] },
						},
					},
				},
				required: ["category", "title", "content"],
			},
			execute: (input: unknown) => {
				const cwd = currentCtx?.cwd ?? process.cwd();
				const db = getDB(cwd);
				return handleMemoryStore(db.getConnection(), cwd, input as MemoryStoreInput);
			},
		});
	} catch { /* tool registration may not be available */ }

	try {
		pi.registerTool({
			name: "memory_recall",
			description: "Recall relevant memories with progressive disclosure based on budget",
			parameters: {
				type: "object",
				properties: {
					context: { type: "string", description: "What context is needed" },
					budget: { type: "number", description: "Max bytes to return (default: 2048)" },
				},
				required: ["context"],
			},
			execute: (input: unknown) => {
				const cwd = currentCtx?.cwd ?? process.cwd();
				const db = getDB(cwd);
				return handleMemoryRecall(db.getConnection(), input as MemoryRecallInput);
			},
		});
	} catch { /* tool registration may not be available */ }

	try {
		pi.registerTool({
			name: "memory_status",
			description: "Get memory status, stats, or manage the memory database",
			parameters: {
				type: "object",
				properties: {
					action: {
						type: "string",
						enum: ["status", "stats", "reindex", "compact", "export"],
						description: "Action to perform",
					},
					format: {
						type: "string",
						enum: ["text", "json"],
						description: "Output format",
					},
				},
				required: ["action"],
			},
			execute: (input: unknown) => {
				const cwd = currentCtx?.cwd ?? process.cwd();
				const db = getDB(cwd);
				return handleMemoryStatus(db.getConnection(), db.dbPath, input as MemoryStatusInput);
			},
		});
	} catch { /* tool registration may not be available */ }
}

import * as fs from "node:fs";
import * as os from "node:os";
import * as path from "node:path";
import test from "node:test";
import assert from "node:assert/strict";
import { MemoryDB } from "../../src/store/sqlite.ts";
import { initSchema } from "../../src/store/schema.ts";
import BetterSqlite3 from "better-sqlite3";
import type Database from "better-sqlite3";

function createTempDir(): string {
	return fs.mkdtempSync(path.join(os.tmpdir(), "pi-memory-test-"));
}

function createTestDB(): { db: Database.Database; dir: string; cleanup: () => void } {
	const dir = createTempDir();
	const dbPath = path.join(dir, "test.db");
	const db = new BetterSqlite3(dbPath) as unknown as Database.Database;
	initSchema(db);
	return {
		db,
		dir,
		cleanup: () => {
			db.close();
			fs.rmSync(dir, { recursive: true, force: true });
		},
	};
}

test("MemoryDB creates .pi-memory directory and opens database", () => {
	const dir = createTempDir();
	try {
		const memDB = new MemoryDB(dir);
		assert.ok(!memDB.isOpen);
		const conn = memDB.open();
		assert.ok(memDB.isOpen);
		assert.ok(fs.existsSync(path.join(dir, ".pi-memory")));
		assert.ok(fs.existsSync(path.join(dir, ".pi-memory", "memory.db")));
		memDB.close();
		assert.ok(!memDB.isOpen);
	} finally {
		fs.rmSync(dir, { recursive: true, force: true });
	}
});

test("MemoryDB getConnection throws if not opened", () => {
	const dir = createTempDir();
	try {
		const memDB = new MemoryDB(dir);
		assert.throws(() => memDB.getConnection(), /not opened/i);
	} finally {
		fs.rmSync(dir, { recursive: true, force: true });
	}
});

test("MemoryDB returns same connection on repeated open calls", () => {
	const dir = createTempDir();
	try {
		const memDB = new MemoryDB(dir);
		const conn1 = memDB.open();
		const conn2 = memDB.open();
		assert.strictEqual(conn1, conn2);
		memDB.close();
	} finally {
		fs.rmSync(dir, { recursive: true, force: true });
	}
});

test("initSchema creates all expected tables", () => {
	const { db, cleanup } = createTestDB();
	try {
		const tables = db.prepare(
			`SELECT name FROM sqlite_master WHERE type='table' ORDER BY name`,
		).all() as Array<{ name: string }>;
		const tableNames = tables.map((t) => t.name);

		assert.ok(tableNames.includes("sources"), "sources table missing");
		assert.ok(tableNames.includes("vocabulary"), "vocabulary table missing");
		assert.ok(tableNames.includes("events"), "events table missing");
		assert.ok(tableNames.includes("solutions"), "solutions table missing");
		assert.ok(tableNames.includes("mental_models"), "mental_models table missing");
	} finally {
		cleanup();
	}
});

test("initSchema creates FTS5 virtual tables", () => {
	const { db, cleanup } = createTestDB();
	try {
		const tables = db.prepare(
			`SELECT name FROM sqlite_master WHERE type='table' AND name LIKE 'chunks%' ORDER BY name`,
		).all() as Array<{ name: string }>;
		const tableNames = tables.map((t) => t.name);

		assert.ok(tableNames.includes("chunks"), "chunks FTS5 table missing");
